return ['domain'=>NULL,'plural-forms'=>'nplurals=2; plural=(n != 1);','language'=>'nl','project-id-version'=>'TranslatePress Multilingual','pot-creation-date'=>'2026-05-25T19:29:27+03:00','po-revision-date'=>'2026-05-25T19:29:27+03:00','x-generator'=>'TranslatePress build (community + OpenRouter), 2026-05-25','messages'=>['Please update the TranslatePress - Multilingual plugin to version %1$s or higher to ensure %2$s functions correctly.'=>'Update de TranslatePress - Multilingual-plugin naar versie %1$s of hoger om te zorgen dat %2$s correct werkt.','Please install and activate the TranslatePress - Multilingual plugin'=>'Installeer en activeer de TranslatePress - Multilingual-plugin','Install & Activate'=>'Installeer & activeer','Please update TranslatePress - Multilingual to version %2$s or newer. Your currently installed version of TranslatePress - Multilingual is no longer compatible with the current version of %1$s.'=>'Update TranslatePress - Multilingual naar versie %2$s of nieuwer. Je huidige versie van TranslatePress - Multilingual is niet langer compatibel met de huidige versie van %1$s.','All TranslatePress functionalities are disabled until then.'=>'Alle TranslatePress-functionaliteiten zijn tot dan uitgeschakeld.','Update Now'=>'Nu bijwerken','This TranslatePress add-on has been migrated to the main plugin and is no longer used. You can delete it.'=>'Deze TranslatePress-add-on is gemigreerd naar de hoofdplugin en wordt niet langer gebruikt. Je kunt deze verwijderen.','<strong>TranslatePress</strong> requires at least PHP version 5.6.20+ to run. It is the <a href="%s">minimum requirement of the latest WordPress version</a>. Please contact your server administrator to update your PHP version.'=>'<strong>TranslatePress</strong> vereist minimaal PHP-versie 5.6.20+ om te draaien. Dit is de <a href="%s">minimale vereiste van de nieuwste WordPress-versie</a>. Neem contact op met je serverbeheerder om je PHP-versie bij te werken.','Advanced'=>'Geavanceerd','Settings saved.'=>'Instellingen opgeslagen.','Are you sure you want to remove this item?'=>'Weet je zeker dat je dit item wilt verwijderen?','Remove'=>'Verwijderen','Add'=>'Toevoegen','Select...'=>'Selecteer...','[%s] Low TranslatePress AI Words'=>'[%s] TranslatePress AI-woorden bijna op','upgrade your plan or get extra AI Words'=>'upgrade je pakket of koop extra AI-woorden','upgrade your plan'=>'upgrade je pakket','TranslatePress AI words are running low on your site.'=>'De TranslatePress AI-woorden op je site raken op.','Current status: %s words remaining'=>'Huidige status: %s woorden over','Once the remaining AI words run out, automatic translation through TranslatePress AI will be paused.'=>'Zodra de resterende AI-woorden op zijn, wordt de automatische vertaling via TranslatePress AI gepauzeerd.','To continue translating your content, please %1$s over at %2$s'=>'Om door te gaan met het vertalen van je content, %1$s op %2$s','Manage Notification: %s'=>'Melding beheren: %s','There is a new version of %1$s available. %2$sView version %3$s details%4$s or %5$supdate now%6$s.'=>'Er is een nieuwe versie van %1$s beschikbaar. %2$sBekijk de details van versie %3$s%4$s of %5$sNu bijwerken%6$s.','There is a new version of %1$s available. %2$sView version %3$s details%4$s.'=>'Er is een nieuwe versie van %1$s beschikbaar. %2$sBekijk de details van versie %3$s%4$s.','To enable updates, please %1$senter your license key%2$s. Need a license key? %3$sPurchase one now%4$s.'=>'Om updates in te schakelen, %1$svoer je licentiesleutel in%2$s. Heb je een licentiesleutel nodig? %3$sKoop er nu een%4$s.','To enable updates, please go to the %1$slicense page%2$s and check that you have a valid license.'=>'Om updates in te schakelen, ga naar de %1$slicentiepagina%2$s en controleer of je een geldige licentie hebt.','To enable updates, your licence needs to be renewed. Please go to the %1$sTranslatePress Account%2$s page and login to renew.'=>'Om updates in te schakelen, moet je licentie worden vernieuwd. Ga naar de %1$sTranslatePress Account%2$s-pagina en log in om te vernieuwen.','You do not have permission to install plugin updates'=>'Je hebt geen toestemming om plugin-updates te installeren','Error'=>'Fout','Your TranslatePress license key is invalid or missing.'=>'Je TranslatePress-licentiesleutel is ongeldig of ontbreekt.','Your license key expired on %s.'=>'Je licentiesleutel is verlopen op %s.','Your license key has been disabled.'=>'Je licentiesleutel is uitgeschakeld.','Your license key is disabled for this URL. Re-enable it from <a target="_blank" href="https://translatepress.com/account/?utm_source=wp-dashboard&utm_medium=client-site&utm_campaign=license-deactivated">https://translatepress.com/account</a> -> Manage Sites.'=>'Je licentiesleutel is uitgeschakeld voor deze URL. Schakel deze opnieuw in via <a target="_blank" href="https://translatepress.com/account/?utm_source=wp-dashboard&utm_medium=client-site&utm_campaign=license-deactivated">https://translatepress.com/account</a> -> Manage Sites.','<p><strong>License key mismatch.</strong> The license you entered doesn’t match the TranslatePress version you have installed.</p><p>Please check that you’ve installed the correct version for your license from your TranslatePress account.</p>'=>'<p><strong>Licentiesleutel komt niet overeen.</strong> De licentie die je hebt ingevoerd, komt niet overeen met de versie van TranslatePress die je hebt geïnstalleerd.</p><p>Controleer of je de juiste versie voor je licentie hebt geïnstalleerd vanuit je TranslatePress-account.</p>','If you have only the free plugin installed but added a paid license, please install the paid plugin from your TranslatePress account.'=>'Als je alleen de gratis plugin hebt geïnstalleerd, maar een betaalde licentie hebt toegevoegd, installeer dan de betaalde plugin vanuit je TranslatePress-account.','Your license key has reached its activation limit.'=>'Je licentiesleutel heeft de activeringslimiet bereikt.','Upgrade your plan to add more sites. %1$sUpgrade now%2$s'=>'Upgrade je pakket om meer sites toe te voegen. %1$sUpgrade nu%2$s','This website is already activated under a free license. Each website can only use one free license.'=>'Deze website is al geactiveerd met een gratis licentie. Elke website kan maar één gratis licentie gebruiken.','An error occurred, please try again.'=>'Er is een fout opgetreden, probeer het opnieuw.','You have successfully activated your license'=>'Je hebt je licentie succesvol geactiveerd.','Others'=>'Overige','Restrict by Language'=>'Beperken op taal','Exclude from Language'=>'Uitsluiten van taal','Restrict element to language'=>'Element beperken tot taal','Show this element only in one language.'=>'Toon dit element alleen in één taal.','Enable translation'=>'Vertaling inschakelen','Allow translation to the corresponding language only if the content is written in the default language.'=>'Sta vertaling naar de bijbehorende taal alleen toe als de inhoud in de standaardtaal is geschreven.','Select language'=>'Taal selecteren','Choose in which language to show this element.'=>'Kies in welke taal je dit element wilt tonen.','Exclude element from language'=>'Element van taal uitsluiten','Exclude this element from specific languages.'=>'Dit element uitsluiten van specifieke talen.','Select languages'=>'Talen selecteren','Choose from which languages to exclude this element.'=>'Kies van welke talen je dit element wilt uitsluiten.','This element will still be visible when you are translating your website through the Translation Editor.'=>'Dit element blijft zichtbaar wanneer je je website vertaalt via de Translation Editor.','The content of this element should be written in the default language.'=>'De inhoud van dit element moet in de standaardtaal worden geschreven.','<strong>TranslatePress</strong> encountered SQL errors. <a href="%s" title="View TranslatePress SQL Errors">Check out the errors</a>.'=>'<strong>TranslatePress</strong> heeft SQL-fouten aangetroffen. <a href="%s" title="View TranslatePress SQL Errors">Bekijk de fouten</a>.','Automatic translation has been disabled.'=>'Automatische vertaling is uitgeschakeld.','Dismiss this notice.'=>'Sluit deze melding.','Logged errors'=>'Gelogde fouten','These are the most recent 5 errors logged by TranslatePress:'=>'Dit zijn de 5 meest recente fouten die door TranslatePress zijn gelogd:','Yes'=>'Ja','Why are these errors occuring'=>'Waarom treden deze fouten op','If TranslatePress detects something wrong when executing queries on your database, it may disable the Automatic Translation feature in order to avoid any extra charging by Google/DeepL. Automatic Translation needs to be manually turned on, after you solve the issues.'=>'Als TranslatePress iets verkeerds detecteert bij het uitvoeren van query\'s op je database, kan het de functie Automatische vertaling uitschakelen om extra kosten door Google/DeepL te voorkomen. Automatische vertaling moet handmatig worden ingeschakeld nadat je de problemen hebt opgelost.','The SQL errors detected can occur for various reasons including missing tables, missing permissions for the SQL user to create tables or perform other operations, problems after site migration or changes to SQL server configuration.'=>'De gedetecteerde SQL-fouten kunnen om verschillende redenen optreden, waaronder ontbrekende tabellen, ontbrekende rechten voor de SQL-gebruiker om tabellen aan te maken of andere bewerkingen uit te voeren, problemen na een sitemigratie of wijzigingen in de SQL-serverconfiguratie.','What you can do in this situation'=>'Wat je in deze situatie kunt doen','Plan A.'=>'Plan A.','Go to Settings -> TranslatePress -> General tab and Save Settings. This will regenerate the tables using your current SQL settings. Check if no more errors occur while browsing your website in a translated language. Look at the timestamps of the errors to make sure you are not seeing the old errors. Only the most recent 5 errors are displayed.'=>'Ga naar Instellingen -> TranslatePress -> tabblad Algemeen en sla de instellingen op. Dit zal de tabellen opnieuw genereren met behulp van je huidige SQL-instellingen. Controleer of er geen fouten meer optreden terwijl je je website in een vertaalde taal bekijkt. Kijk naar de tijdstempels van de fouten om er zeker van te zijn dat je geen oude fouten ziet. Alleen de 5 meest recente fouten worden weergegeven.','Plan B.'=>'Plan B.','If your problem isn\'t solved, try the following steps:'=>'Als je probleem niet is opgelost, probeer dan de volgende stappen:','Create a backup of your database'=>'Maak een back-up van je database','Create a copy of each translation table where you encounter errors. You can copy the table within the same database (trp_dictionary_en_us_es_es_COPY for example) -- perform this step only if you want to keep the current translations'=>'Maak een kopie van elke vertaaltabel waarin je fouten tegenkomt. Je kunt de tabel binnen dezelfde database kopiëren (bijvoorbeeld trp_dictionary_en_us_es_es_COPY) -- voer deze stap alleen uit als je de huidige vertalingen wilt behouden','Remove the trouble tables by executing the DROP function on them'=>'Verwijder de betreffende tabellen door de DROP-functie erop uit te voeren','Go to Settings -> TranslatePress -> General tab and Save Settings. This will regenerate the tables using your current SQL server.'=>'Ga naar Instellingen -> TranslatePress -> tabblad Algemeen en sla de instellingen op. Dit zal de tabellen opnieuw genereren met behulp van je huidige SQL-server.','Copy the relevant content from the duplicated tables (trp_dictionary_en_us_es_es_COPY for example) in the newly generated table (trp_dictionary_en_us_es_es) -- perform this step only if you want to keep the current translations'=>'Kopieer de relevante inhoud uit de gedupliceerde tabellen (bijvoorbeeld trp_dictionary_en_us_es_es_COPY) naar de nieuw gegenereerde tabel (trp_dictionary_en_us_es_es) -- voer deze stap alleen uit als je de huidige vertalingen wilt behouden','Test it to see if everything is working. If something went wrong, you can restore the backup that you\'ve made at the first step. Check if no more errors occur while browsing your website in a translated language. Look at the timestamps of the errors to make sure you are not seeing the old errors. Only the most recent 5 errors are displayed.'=>'Test het om te zien of alles werkt. Als er iets mis is gegaan, kun je de back-up die je in de eerste stap hebt gemaakt, herstellen. Controleer of er geen fouten meer optreden terwijl je je website in een vertaalde taal bekijkt. Kijk naar de tijdstempels van de fouten om er zeker van te zijn dat je geen oude fouten ziet. Alleen de 5 meest recente fouten worden weergegeven.','Plan C.'=>'Plan C.','If your problem still isn\'t solved, try asking your hosting about your errors. The most common issue is missing permissions for the SQL user, such as the Create Tables permission.'=>'Als je probleem nog steeds niet is opgelost, probeer dan je hostingprovider te vragen naar deze fouten. Het meest voorkomende probleem is ontbrekende rechten voor de SQL-gebruiker, zoals het recht om tabellen aan te maken.','Could not install. Try again from <a href="%s" >Plugins Dashboard.</a>'=>'Kan niet installeren. Probeer het opnieuw vanaf <a href="%s" >Plugins-dashboard.</a>','Active'=>'Actief','Permission denied.'=>'Toestemming geweigerd.','Invalid nonce.'=>'Ongeldige nonce.','Settings scope unknown.'=>'Scope van instellingen onbekend.','Legacy disabled.'=>'Legacy uitgeschakeld.','Language Switcher'=>'Taalwisselaar','Change language to %s'=>'Taal wijzigen naar %s','Automatic Translation'=>'Automatische vertaling','DeepL'=>'DeepL','Unsupported languages'=>'Niet-ondersteunde talen','The selected automatic translation engine does not provide support for these languages.<br>You can still manually translate pages in these languages using the Translation Editor.'=>'De geselecteerde automatische vertaalengine biedt geen ondersteuning voor deze talen.<br>Je kunt pagina\'s in deze talen nog steeds handmatig vertalen met de vertaaleditor.','API key validation failed.'=>'Validatie van API-sleutel mislukt.','API key verification was successful.'=>'Verificatie van API-sleutel geslaagd.','Please enter your Google Translate key.'=>'Voer je Google Translate-sleutel in.','Please enter your DeepL API key.'=>'Voer je DeepL API-sleutel in.','Not TranslatePress onboarding page.'=>'Geen TranslatePress onboarding-pagina.','Step %s does not exist'=>'Stap %s bestaat niet','Welcome'=>'Welkom','Add Languages'=>'Talen toevoegen','Enable Addons'=>'Add-ons inschakelen','Finalize'=>'Afronden','Exit Setup'=>'Setup afsluiten','Upgrade'=>'Upgraden','Nothing here'=>'Niets hier','Your <strong>TranslatePress</strong> license is missing or invalid. <br/>Please %1$sregister your copy%2$s to enable automatic website translation via TranslatePress AI, premium addons, automatic updates and support. Need a license key? %3$sPurchase one now%4$s'=>'Uw <strong>TranslatePress</strong>-licentie ontbreekt of is ongeldig. <br/>%1$sRegistreer alstublieft uw exemplaar%2$s om automatische websitevertaling via TranslatePress AI, premium add-ons, automatische updates en ondersteuning in te schakelen. Een licentiesleutel nodig? %3$sKoop er nu een%4$s','Your <strong>TranslatePress</strong> license will expire on %1$s. Please %2$sRenew Your Licence%3$s to continue receiving access to automatic translations via TP AI, premium addons, product downloads and automatic updates. %4$sRenew Now%5$s'=>'Uw <strong>TranslatePress</strong>-licentie verloopt op %1$s. %2$sVerleng uw licentie%3$s om toegang te blijven houden tot automatische vertalingen via TP AI, premium add-ons, productdownloads en automatische updates. %4$sNu verlengen%5$s','Error: '=>'Fout: ','Something went wrong, please try again.'=>'Er is iets misgegaan, probeer het opnieuw.','Your <strong>TranslatePress</strong> license has expired. <br/>Please %1$sRenew Your Licence%2$s to continue receiving access to automatic translations via TranslatePress AI, premium addons, product downloads, and automatic updates. %3$sRenew now %4$s'=>'Uw <strong>TranslatePress</strong>-licentie is verlopen. <br/>%1$sVerleng uw licentie%2$s om toegang te blijven houden tot automatische vertalingen via TranslatePress AI, premium add-ons, productdownloads en automatische updates. %3$sNu verlengen %4$s','License key mismatch. The license you entered doesn’t match the <strong>%1$s</strong> version you have installed. <br/>Please check that you’ve installed the correct version for your license from your %2$sTranslatePress account%3$s.'=>'Licentiesleutel komt niet overeen. De ingevoerde licentie komt niet overeen met de geïnstalleerde <strong>%1$s</strong>-versie. <br/>Controleer of u de juiste versie voor uw licentie hebt geïnstalleerd via uw %2$sTranslatePress Account%3$s.','<br/>If you have only the free plugin installed but added a paid license, please install the paid plugin from your TranslatePress account.'=>'<br/>Als u alleen de gratis plugin hebt geïnstalleerd, maar een betaalde licentie hebt toegevoegd, installeer dan de betaalde plugin via uw TranslatePress Account.','You have reached the activation limit for your <strong>%1$s</strong> license. <br/>Manage your active sites from %2$s your account %3$s.'=>'U hebt het activeringslimiet bereikt voor uw <strong>%1$s</strong>-licentie. <br/>Beheer uw actieve sites vanuit %2$s uw account %3$s.','Your license is disabled for this URL. Re-enable it from <a target="_blank" href="https://translatepress.com/account/?utm_source=wp-dashboard&utm_medium=client-site&utm_campaign=license-deactivated">https://translatepress.com/account</a> -> Manage Sites.'=>'Uw licentie is uitgeschakeld voor deze URL. Heractiveer deze via <a target="_blank" href="https://translatepress.com/account/?utm_source=wp-dashboard&utm_medium=client-site&utm_campaign=license-deactivated">https://translatepress.com/account</a> -> Sites beheren.','%1$s automatic translation requires an active license. Please %2$srenew%3$s your license or purchase a new one %4$shere%5$s.'=>'Automatische vertaling met %1$s vereist een actieve licentie. %2$sVerleng%3$s uw licentie of koop een nieuwe %4$shier%5$s.','Please %1$senter%2$s your license key to enable %3$s automatic translation.'=>'%1$sVoer%2$s uw licentiesleutel in om automatische vertaling met %3$s in te schakelen.','You have less than 5,000 TranslatePress AI words remaining. To continue automatically translating your website, please %spurchase additional AI words at a discount from your account%s.'=>'U hebt minder dan 5.000 TranslatePress AI-woorden resterend. Om uw website automatisch te blijven vertalen, %skoop extra AI-woorden met korting via uw account%s.',' Error: '=>' Fout: ','This website is already activated under a free license. Each website can only use one free license. Please upgrade to a premium plan for more TranslatePress AI words from %1$s your account %2$s.'=>'Deze website is al geactiveerd met een gratis licentie. Elke website kan slechts één gratis licentie gebruiken. Upgrade naar een premiumplan voor meer TranslatePress AI-woorden vanuit %1$s uw account %2$s.','You do not have a valid license for <strong>TranslatePress</strong>. %1$sGet one for free%2$s to get access to TranslatePress AI.'=>'U hebt geen geldige licentie voor <strong>TranslatePress</strong>. %1$sKrijg er gratis een%2$s om toegang te krijgen tot TranslatePress AI.','<strong>NEW:</strong> The <strong>Different Domain per Language</strong> add-on is here! Boost your global SEO and create a local experience with country-specific domains like .de or .fr. Upgrade to <a href="https://translatepress.com/pricing/?utm_source=wp-dashboard&utm_medium=client-site&utm_campaign=new-addon-ddpl-upsell" target="_blank">TranslatePress Business or Developer</a> to access it + more premium perks!'=>'<strong>NIEUW:</strong> De <strong>Different Domain per Language</strong>-add-on is hier! Verbeter uw globale SEO en creëer een lokale ervaring met landspecifieke domeinen zoals .de of .fr. Upgrade naar <a href="https://translatepress.com/pricing/?utm_source=wp-dashboard&utm_medium=client-site&utm_campaign=new-addon-ddpl-upsell" target="_blank">TranslatePress Business of Developer</a> om er toegang toe te krijgen + meer premium voordelen!','<strong>NEW:</strong> The <strong>Different Domain per Language</strong> add-on is here! Boost your global SEO and create a local experience with country-specific domains like .de or .fr. <a href="https://translatepress.com/docs/addons/different-domain-per-language/?utm_source=wp-dashboard&utm_medium=client-site&utm_campaign=new-addon-ddpl" target="_blank">Learn more</a>.'=>'<strong>NIEUW:</strong> De <strong>Different Domain per Language</strong>-add-on is hier! Verbeter uw globale SEO en creëer een lokale ervaring met landspecifieke domeinen zoals .de of .fr. <a href="https://translatepress.com/docs/addons/different-domain-per-language/?utm_source=wp-dashboard&utm_medium=client-site&utm_campaign=new-addon-ddpl" target="_blank">Meer informatie</a>.','The daily quota for machine translation characters exceeded. Please check the <strong>TranslatePress -> <a href="%s">Automatic Translation</a></strong> page for more information.'=>'Het dagelijkse quotum voor machinevertalingstekens is overschreden. Controleer de <strong>TranslatePress -> <a href="%s">Automatische vertaling</a></strong>-pagina voor meer informatie.','Marketing optin'=>'Marketingopt-in','Opt in to our security and feature updates notifications, and non-sensitive diagnostic tracking.'=>'Schrijf je in voor meldingen over beveiligings- en functie-updates, en voor niet-gevoelige diagnostische tracking.','TranslatePress Preferred User Language'=>'TranslatePress-voorkeurstaal gebruiker','Preferred language to navigate the site'=>'Voorkeurstaal om de site te bezoeken','The language is automatically set based by the last visited language by the user.'=>'De taal wordt automatisch ingesteld op basis van de laatst bezochte taal van de gebruiker.','Always use this language'=>'Gebruik altijd deze taal','By checking this setting the preferred language will remain the one selected above, without the possibility of being changed in the frontend.<br>This language will be used in different operations such as sending email to the user.'=>'Door deze instelling aan te vinken blijft de voorkeurstaal de hierboven geselecteerde taal, zonder dat deze in de frontend kan worden gewijzigd.<br>Deze taal wordt gebruikt voor verschillende handelingen, zoals het verzenden van e-mail naar de gebruiker.','Hello! Seems like you\'ve been using <strong>TranslatePress</strong> for a while now to translate your website. That\'s awesome! '=>'Hallo! Het lijkt erop dat je <strong>TranslatePress</strong> al een tijdje gebruikt om je website te vertalen. Dat is geweldig! ','If you can spare a few moments to rate it on WordPress.org it would help us a lot (and boost my motivation).'=>'Als je een paar minuten kunt vrijmaken om het te beoordelen op WordPress.org, zou dat ons enorm helpen (en mijn motivatie een boost geven).','~ Razvan, developer of TranslatePress'=>'~ Razvan, ontwikkelaar van TranslatePress','Rate TranslatePress on WordPress.org plugin page'=>'Beoordeel TranslatePress op de pluginpagina van WordPress.org','Ok, I will gladly help!'=>'Ok, ik help graag!','No, thanks.'=>'Nee, bedankt.','Full Language Names'=>'Volledige taalnamen','Short Language Names'=>'Korte taalnamen','Flags with Full Language Names'=>'Vlaggen met volledige taalnamen','Flags with Short Language Names'=>'Vlaggen met korte taalnamen','Only Flags'=>'Alleen vlaggen','Full Language Names No HTML'=>'Volledige taalnamen zonder HTML','Bottom Right'=>'Rechtsonder','Bottom Left'=>'Linksonder','Top Right'=>'Rechtsboven','Top Left'=>'Linksboven','Dark'=>'Donker','Light'=>'Licht','Deactivate'=>'Deactiveren','Activate'=>'Activeren','Invalid language code. Please try again.'=>'Ongeldige taalcode. Probeer het opnieuw.','Language codes can contain only A-Z a-z 0-9 - _ characters. Check your language codes in TranslatePress General Settings.'=>'Taalcodes mogen alleen de tekens A-Z a-z 0-9 - _ bevatten. Controleer je taalcodes in de algemene instellingen van TranslatePress.','Error! Duplicate URL slug values.'=>'Fout! Dubbele URL-slugwaarden.','You cannot select two languages that have the same <a href="https://en.wikipedia.org/wiki/List_of_ISO_639-1_codes" target="_blank">iso code</a> but different formalities because doing so will lead to duplicate <a href="https://developers.google.com/search/docs/specialty/international/localized-versions" target="_blank">hreflang tags</a>.'=>'Je kunt niet twee talen selecteren die dezelfde <a href="https://en.wikipedia.org/wiki/List_of_ISO_639-1_codes" target="_blank">iso-code</a> hebben maar verschillende formaliteiten, omdat dit zal leiden tot dubbele <a href="https://developers.google.com/search/docs/specialty/international/localized-versions" target="_blank">hreflang-tags</a>.','Duplicate language detected.<br>Each language can only be added once to ensure accurate translation management.<br> Please change the duplicate language entry and try again. '=>'Dubbele taal gedetecteerd.<br>Elke taal kan maar één keer worden toegevoegd om nauwkeurig vertaalbeheer te garanderen.<br> Wijzig de dubbele taalinvoer en probeer het opnieuw. ','Current Language'=>'Huidige taal','Opposite Language'=>'Tegenovergestelde taal','General'=>'Algemeen','Translate Site'=>'Site vertalen','Addons'=>'Add-ons','License'=>'Licentie','Settings'=>'Instellingen','Activate License'=>'Licentie activeren','Pro Features'=>'Pro-functies','Need Help?'=>'Hulp nodig?','Recent community discussions'=>'Recente community-discussies','Loading...'=>'Laden...','Unable to load forum posts'=>'Kan forumberichten niet laden','Ask a Question'=>'Stel een vraag','View All Topics'=>'Bekijk alle onderwerpen','by'=>'door','Have a question?'=>'Heb je een vraag?','Get help directly from the plugin developers, suggest improvements, or share your feedback!'=>'Krijg direct hulp van de plugin-ontwikkelaars, stel verbeteringen voor of deel je feedback!','Tip for faster help:'=>'Tip voor snellere hulp:','Include what you tried, what you expected, and what happened. Screenshots help!'=>'Vermeld wat je hebt geprobeerd, wat je verwachtte en wat er gebeurde. Schermafbeeldingen helpen!','Toggle support chat'=>'Supportchat aan/uit','Ask the community'=>'Vraag het aan de community','Close'=>'Sluiten','Empty feed response'=>'Lege feed-reactie','Unable to parse feed'=>'Kan feed niet verwerken','Just now'=>'Zojuist','%d hour ago'=>'%d uur geleden' . "\0" . '%d uur geleden','%d day ago'=>'%d dag geleden' . "\0" . '%d dagen geleden','Source'=>'Bron','Srcset'=>'Srcset','Alt attribute'=>'Alt-attribuut','Title attribute'=>'Titelattribuut','Anchor link'=>'Ankerlink','Placeholder attribute'=>'Placeholder-attribuut','Submit attribute'=>'Verzendattribuut','Text'=>'Tekst','Video Poster'=>'Videoposter','plural form'=>'meervoudsvorm','one'=>'één','few'=>'enkele','many'=>'veel','other'=>'overig','Saved'=>'Opgeslagen','Save'=>'Opslaan','Saving translation...'=>'Bezig met opslaan van vertaling...','You have unsaved changes!'=>'Je hebt niet-opgeslagen wijzigingen!','Discard changes'=>'Wijzigingen negeren','Discard All'=>'Alles negeren','Loading Strings...'=>'Tekenreeksen laden...','Select string to translate...'=>'Selecteer een tekenreeks om te vertalen...','Close Editor'=>'Editor sluiten','From'=>'Van','To'=>'Naar','Add Media'=>'Media toevoegen','Other languages'=>'Andere talen','Context'=>'Context','View Website As'=>'Website bekijken als','Available in our Pro Versions'=>'Beschikbaar in onze Pro-versies','Select or Upload Media'=>'Media selecteren of uploaden','Use this media'=>'Deze media gebruiken','Translate'=>'Vertalen','Translate entire block element'=>'Heel blok-element vertalen','Split block to translate strings individually'=>'Blok splitsen om tekenreeksen afzonderlijk te vertalen','Save changes to translation. Shortcut: CTRL(⌘) + S'=>'Wijzigingen in vertaling opslaan. Sneltoets: CTRL(⌘) + S','Navigate to next string in dropdown list. Shortcut: CTRL(⌘) + ALT + Right Arrow'=>'Navigeer naar de volgende tekenreeks in de dropdown-lijst. Sneltoets: CTRL(⌘) + ALT + Pijl naar rechts','Navigate to previous string in dropdown list. Shortcut: CTRL(⌘) + ALT + Left Arrow'=>'Navigeer naar de vorige tekenreeks in de dropdown-lijst. Sneltoets: CTRL(⌘) + ALT + Pijl naar links','Discard all changes. Shortcut: CTRL(⌘) + ALT + Z'=>'Alle wijzigingen verwerpen. Sneltoets: CTRL(⌘) + ALT + Z','Discard changes to this text box. To discard changes to all text boxes use shortcut: CTRL(⌘) + ALT + Z'=>'Wijzigingen in dit tekstvak verwerpen. Om wijzigingen in alle tekstvakken te verwerpen, gebruik de sneltoets: CTRL(⌘) + ALT + Z','Dismiss tooltip'=>'Tooltip sluiten','Quick Intro'=>'Korte introductie','Are you sure you want to split this phrase into smaller parts?'=>'Weet je zeker dat je deze zin in kleinere delen wilt splitsen?','This string is not ready for translation yet. <br>Try again in a moment...'=>'Deze tekenreeks is nog niet klaar om te vertalen. <br>Probeer het over een ogenblik opnieuw...','For this option to work, please update the Browse as other role add-on to the latest version.'=>'Om deze optie te laten werken, werk je de Browse as other role-add-on bij naar de nieuwste versie.','To translate slugs, please update the SEO Pack add-on to the latest version.'=>'Om slugs te vertalen, update je de SEO Pack add-on naar de nieuwste versie.','You can add a new language from <a href="%s">Settings->TranslatePress</a>'=>'Je kunt een nieuwe taal toevoegen via <a href="%s">Instellingen->TranslatePress</a>','However, you can still use TranslatePress to <strong style="background: #f5fb9d;">modify gettext strings</strong> available in your page.'=>'Je kunt TranslatePress echter nog steeds gebruiken om <strong style="background: #f5fb9d;">gettext-tekenreeksen te wijzigen</strong> die op je pagina beschikbaar zijn.','Strings that are user-created cannot be modified, only those from themes and plugins.'=>'Door gebruikers aangemaakte tekenreeksen kunnen niet worden gewijzigd, alleen die van thema\'s en plugins.','Extra Translation Features'=>'Extra vertaalfuncties','Support for 130+ Extra Languages'=>'Ondersteuning voor 130+ extra talen','Access to TranslatePress AI'=>'Toegang tot TranslatePress AI','Translate SEO Title, Description, Slug'=>'SEO-titel, beschrijving en slug vertalen','Publish only when translation is complete'=>'Alleen publiceren als de vertaling voltooid is','Translate by Browsing as User Role'=>'Vertalen door te browsen als gebruikersrol','Different Menu Items for each Language'=>'Verschillende menu-items voor elke taal','Automatic User Language Detection'=>'Automatische detectie van de gebruikerstaal','Upgrade to PRO'=>'Upgrade naar PRO','Upgrade to PRO with our biggest discount of the year!'=>'Upgrade naar PRO met onze grootste korting van het jaar!','This Black Friday, get access to these features and more at a fraction of the costs:'=>'Deze Black Friday krijg je toegang tot deze functies en meer voor een fractie van de kosten:','No available suggestions'=>'Geen beschikbare suggesties','Suggestions from translation memory'=>'Suggesties uit het vertaalgeheugen','Click to Copy'=>'Klik om te kopiëren','Human Translation'=>'Menselijke vertaling','Machine Translation'=>'Machinevertaling','Text on this page is %s% translated into all languages.'=>'Tekst op deze pagina is %s% vertaald in alle talen.','%1$s% of text on this page is translated into %2$s.'=>'%1$s% van de tekst op deze pagina is vertaald in %2$s.','This page is %1$s% translated into %2$s.'=>'Deze pagina is %1$s% vertaald in %2$s.','The slug that you are trying to edit is present in other slug types:%s%. Editing it will replace each occurrence, regardless of the current type.'=>'De slug die je probeert te bewerken, komt voor in andere slug-typen:%s%. Als je deze bewerkt, wordt elke instantie vervangen, ongeacht het huidige type.','Hover any text on the page, click %s,<br> then modify the translation in the sidebar.'=>'Houd de muisaanwijzer boven een tekst op de pagina, klik op %s,<br> en wijzig daarna de vertaling in de zijbalk.','Don\'t forget to Save Translation. Use keyboard shortcut CTRL(⌘) + S'=>'Vergeet niet de vertaling op te slaan. Gebruik de sneltoets CTRL(⌘) + S','Switch language to see the translation changes directly on the page.'=>'Wissel van taal om de vertaalwijzigingen direct op de pagina te zien.','Search for any text in this page in the dropdown.'=>'Zoek in de dropdown naar een tekst op deze pagina.','Your %s license has <span class="trp-license-status-emphasized">expired</span>.'=>'Je %s-licentie is <span class="trp-license-status-emphasized">verlopen</span>.','Please renew your license to continue receiving access to TranslatePress AI, premium addons, automatic updates and support.'=>'Vernieuw je licentie om toegang te blijven houden tot TranslatePress AI, premium add-ons, automatische updates en ondersteuning.','Renew Now'=>'Nu vernieuwen','<strong>This Black Friday, renew your license at a special price</strong> to continue receiving access to product downloads, automatic updates, and support.'=>'<strong>Deze Black Friday vernieuw je licentie tegen een speciale prijs</strong> om toegang te blijven houden tot productdownloads, automatische updates en ondersteuning.','Get Deal'=>'Aanbieding pakken','Your %s license was <span class="trp-license-status-emphasized">refunded</span>.'=>'Je %s-licentie is <span class="trp-license-status-emphasized">terugbetaald</span>.','Please purchase a new license to continue receiving access to TranslatePress AI, premium addons, automatic updates and support.'=>'Koop een nieuwe licentie om toegang te blijven houden tot TranslatePress AI, premium add-ons, automatische updates en ondersteuning.','Purchase a new license'=>'Koop een nieuwe licentie','Your %s license is <span class="trp-license-status-emphasized">missing or invalid</span>.'=>'Je %s-licentie is <span class="trp-license-status-emphasized">ontbrekend of ongeldig</span>.','Please enter a valid license to get access to TranslatePress AI, premium addons, automatic updates and support. Need a license key? %1$sPurchase one now%2$s'=>'Voer een geldige licentie in voor toegang tot TranslatePress AI, premium add-ons, automatische updates en ondersteuning. Heb je een licentiesleutel nodig? %1$sKoop er nu een%2$s','Enter a valid license'=>'Voer een geldige licentie in','Slugs'=>'Slugs','Meta Information'=>'Meta-informatie','String List'=>'Tekenreeksenlijst','Gettext Strings'=>'Gettext-tekenreeksen','Images'=>'Afbeeldingen','Videos'=>'Video\'s','Audios'=>'Audio','Dynamically Added Strings'=>'Dynamisch toegevoegde tekenreeksen','Translation Editor'=>'Vertaal-editor','Edit translations by visually selecting them on each site page'=>'Bewerk vertalingen door ze visueel te selecteren op elke pagina van de site','String Translation'=>'Tekenreeksen vertalen','Edit url slug translations, plugins and theme translation (emails, forms etc.)'=>'URL-slugvertalingen, plugin- en themavertalingen bewerken (e-mails, formulieren etc.)','Current User'=>'Huidige gebruiker','Logged Out'=>'Uitgelogd','Translate Page'=>'Pagina vertalen','Add a New Language'=>'Een nieuwe taal toevoegen','Get a Free AI License'=>'Gratis AI-licentie aanvragen','Your License is Invalid'=>'Je licentie is ongeldig','Get More AI Words (%d left)'=>'Meer AI-woorden ophalen (%d resterend)','Opens post in the translation editor. Post must be saved as draft or published beforehand.'=>'Opent het bericht in de vertaaleditor. Het bericht moet van tevoren als concept zijn opgeslagen of gepubliceerd zijn.','Security check'=>'Beveiligingscontrole','<strong>Warning:</strong> Some strings have possibly incorrectly encoded characters. This may result in breaking the queries, rendering the page untranslated in live mode. Consider revising the following strings or their method of outputting.'=>'<strong>Waarschuwing:</strong> Sommige strings bevatten mogelijk onjuist gecodeerde tekens. Dit kan de query\'s doen falen, waardoor de pagina in live modus onvertaald blijft. Overweeg om de volgende strings of hun uitvoermethode te herzien.','TranslatePress data update'=>'TranslatePress-gegevensupdate','We need to update your translations database to the latest version.'=>'We moeten je vertalingendatabase bijwerken naar de nieuwste versie.','Updating will allow editing translations of localized text from plugins and theme. Existing translation will still work as expected.'=>'Bijwerken maakt het mogelijk om vertalingen te bewerken van gelokaliseerde tekst uit plugins en het thema. Bestaande vertalingen blijven naar verwachting werken.','IMPORTANT: It is strongly recommended to first backup the database!
Are you sure you want to continue?'=>'BELANGRIJK: Het wordt sterk aanbevolen om eerst een back-up van de database te maken!\\nWeet je zeker dat je wilt doorgaan?','Run the updater'=>'Updater uitvoeren','Updating will allow editing translations of slugs. Existing translation will still work as expected.'=>'Bijwerken maakt het bewerken van vertalingen van slugs mogelijk. Bestaande vertalingen blijven naar verwachting werken.','Please activate the SEO Addon from <br/>WordPress -> Settings -> TranslatePress -> Addons section'=>'Activeer de SEO-addon via <br/>WordPress -> Instellingen -> TranslatePress -> Addons-sectie','Go to Addons'=>'Ga naar Addons','The SEO Pack add-on allows translation of all the URL slugs:'=>'De SEO Pack add-on maakt vertaling van alle URL-slugs mogelijk:','Taxonomy slugs'=>'Taxonomie-slugs','Term slugs'=>'Term-slugs','Post slugs (this includes pages and custom post types)'=>'Bericht-slugs (dit omvat pagina\'s en aangepaste berichttypen)','Post type base slugs'=>'Basis-slugs van berichttypen','WooCommerce slugs'=>'WooCommerce-slugs','The SEO Pack add-on is available with ALL premium versions of the plugin.'=>'De SEO Pack add-on is beschikbaar bij ALLE premium versies van de plugin.','Upgrade to Pro'=>'Upgraden naar Pro','Description'=>'Beschrijving','Article Section'=>'Artikelsectie','Article Tag'=>'Artikeltag','OG Title'=>'OG-titel','OG Site Name'=>'OG-sitenaam','OG Description'=>'OG-beschrijving','OG Image Alt'=>'OG-afbeelding alt-tekst','Twitter Title'=>'Twitter-titel','Twitter Description'=>'Twitter-beschrijving','Twitter Image Alt'=>'Twitter-afbeelding alt-tekst','Page Title'=>'Paginatitel','Dublin Core Title'=>'Dublin Core-titel','Dublin Core Description'=>'Dublin Core-beschrijving','OG Image'=>'OG-afbeelding','OG Image Secure URL'=>'OG-afbeelding beveiligde URL','Twitter Image'=>'Twitter-afbeelding','Removing cdata dictionary strings for language %s...'=>'CDATA-woordenboekstrings verwijderen voor taal %s...','Removing untranslated dictionary links for language %s...'=>'Onvertaalde woordenboeklinks voor taal %s verwijderen...','Removing duplicated gettext strings for language %s...'=>'Dubbele Gettext-strings verwijderen voor taal %s...','Removing duplicated dictionary strings for language %s...'=>'Dubbele woordenboekstrings verwijderen voor taal %s...','Removing untranslated dictionary strings where translation is available for language %s...'=>'Onvertaalde woordenboekstrings verwijderen waarvoor een vertaling beschikbaar is voor taal %s...','Inserting original strings for language %s...'=>'Originele strings invoegen voor taal %s...','Cleaning original strings table for language %s...'=>'Tabel met originele strings opschonen voor taal %s...','Updating original string ids for language %s...'=>'ID\'s van originele strings bijwerken voor taal %s...','Regenerating original meta table for language %s...'=>'Tabel met originele meta voor taal %s opnieuw genereren...','Cleaning original meta table for language %s...'=>'Tabel met originele meta voor taal %s opschonen...','Replacing original id NULL with value for language %s...'=>'Originele ID NULL voor taal %s vervangen door waarde...','Inserting gettext original strings for language %s...'=>'Originele Gettext-strings invoegen voor taal %s...','Cleaning gettext original strings table for language %s...'=>'Tabel met originele Gettext-strings opschonen voor taal %s...','Updating gettext original string ids for language %s...'=>'ID\'s van originele Gettext-strings bijwerken voor taal %s...','Migrating taxonomy and post type base slugs to new table structure...'=>'Basis-slugs van taxonomieën en berichttypen migreren naar nieuwe tabelstructuur...','Migrating post slugs to new table structure for language %s...'=>'Bericht-slugs migreren naar nieuwe tabelstructuur voor taal %s...','Migrating term slugs to new table structure for language %s...'=>'Term-slugs migreren naar nieuwe tabelstructuur voor taal %s...','Finishing up...'=>'Afronden...','Database optimization did not complete successfully. We recommend restoring the original database or <a href="%s" >trying again.</a>'=>'Database-optimalisatie is niet succesvol voltooid. We raden aan om de originele database te herstellen of <a href="%s" >opnieuw te proberen.</a>','Update aborted! Your user account doesn\'t have the capability to perform database updates.'=>'Update afgebroken! Je gebruikersaccount heeft niet de juiste rechten om database-updates uit te voeren.','Update aborted! Invalid nonce.'=>'Update afgebroken! Ongeldige nonce.','Update aborted! Incorrect action.'=>'Update afgebroken! Onjuiste actie.','Update aborted! Incorrect language code.'=>'Update afgebroken! Onjuiste taalcode.','Updating database to version %s+'=>'Database bijwerken naar versie %s+','Processing table for language %s...'=>'Tabel verwerken voor taal %s...','Back to TranslatePress Settings'=>'Terug naar TranslatePress-instellingen','Successfully updated database!'=>'Database succesvol bijgewerkt!',' done.'=>' klaar.','All individual TranslatePress add-on plugins <a href="%1$s" target="_blank">have been discontinued</a> and are now included in the premium Personal, Business and Developer versions of TranslatePress. Please log into your <a href="%2$s" target="_blank">account page</a>, download the new premium version and install it. Your individual addons settings will be ported over.'=>'Alle individuele TranslatePress add-on plugins <a href="%1$s" target="_blank">zijn stopgezet</a> en zijn nu opgenomen in de premium Personal, Business en Developer versies van TranslatePress. Log in op je <a href="%2$s" target="_blank">accountpagina</a>, download de nieuwe premium versie en installeer deze. Je instellingen voor individuele add-ons worden overgenomen.','Brand-new Language Switcher Settings are here!'=>'Splinternieuwe taalwisselaar-instellingen zijn hier!','Explore pre-made templates, switch colors, flag styles, spacing, layouts & more. Use the live preview to perfect your switcher in seconds.'=>'Ontdek kant-en-klare sjablonen, kleuren, vlagstijlen, afstand, lay-outs en meer. Gebruik de live voorvertoning om je taalwisselaar in enkele seconden te perfectioneren.','Start customizing'=>'Start met aanpassen','Read documentation'=>'Lees documentatie','TranslatePress'=>'TranslatePress','<strong>TranslatePress</strong> requires <strong><a href="http://php.net/manual/en/book.mbstring.php">Multibyte String PHP library</a></strong>. Please contact your server administrator to install it on your server.'=>'<strong>TranslatePress</strong> vereist de <strong><a href="http://php.net/manual/en/book.mbstring.php">Multibyte String PHP-bibliotheek</a></strong>. Neem contact op met je serverbeheerder om deze op je server te installeren.','Detected long query limitation on WPEngine hosting. Some large pages may appear untranslated. You can remove limitation by adding the following to your site’s wp-config.php: define( \'WPE_GOVERNOR\', false ); '=>'Beperking voor lange queries gedetecteerd op WPEngine hosting. Sommige grote pagina\'s kunnen onvertaald verschijnen. Je kunt de beperking opheffen door het volgende toe te voegen aan de wp-config.php van je site: define( \'WPE_GOVERNOR\', false ); ','Custom Language Flag'=>'Aangepaste taalvlag','The Language code of the added custom language cannot be empty.'=>'De taalcode van de toegevoegde aangepaste taal mag niet leeg zijn.','The Language code of the added custom language is invalid.'=>'De taalcode van de toegevoegde aangepaste taal is ongeldig.','The Automatic Translation Code of the added custom language is invalid.'=>'De automatische vertaalcode van de toegevoegde aangepaste taal is ongeldig.','TranslatePress Add-ons'=>'TranslatePress add-ons','You must first purchase this version to have access to the addon %1$shere%2$s'=>'Je moet eerst deze versie aanschaffen om toegang te krijgen tot de add-on %1$shier%2$s','Please %1$senter your license%2$s key first, to activate this addon.'=>'%1$sVoer eerst je licentiesleutel in%2$s om deze addon te activeren.','You need an active license to have access to the addon. Renew or purchase a new one %1$shere%2$s.'=>'Je hebt een actieve licentie nodig voor toegang tot deze addon. Verleng of koop een nieuwe %1$shier%2$s.','Advanced Add-ons'=>'Geavanceerde add-ons','These addons extend your translation plugin and are available in the Developer, Business and Personal plans.'=>'Deze addons breiden je vertaalplugin uit en zijn beschikbaar in de Developer-, Business- en Personal-abonnementen.','SEO Pack'=>'SEO Pack','SEO Pack (Legacy)'=>'SEO Pack (Legacy)','SEO support for page slug, page title, description and facebook and twitter social graph information. The HTML lang attribute is properly set.'=>'SEO-ondersteuning voor pagina-slug, paginatitel, beschrijving en social graph-informatie voor Facebook en Twitter. Het HTML lang-attribuut is correct ingesteld.','Multiple Languages'=>'Meerdere talen','Add as many languages as you need for your project to go global. Publish your language only when all your translations are done.'=>'Voeg zoveel talen toe als je nodig hebt om je project wereldwijd te maken. Publiceer je taal pas wanneer al je vertalingen klaar zijn.','Pro Add-ons'=>'Pro-add-ons','These addons extend your translation plugin and are available in the Business and Developer plans.'=>'Deze addons breiden je vertaalplugin uit en zijn beschikbaar in de Business- en Developer-abonnementen.','DeepL Automatic Translation'=>'Automatische DeepL-vertaling','Automatically translate your website through the DeepL API.'=>'Vertaal je website automatisch via de DeepL API.','Prompts visitors to switch to their preferred language based on their browser settings or IP address and remembers the last visited language.'=>'Vraagt bezoekers om over te schakelen naar hun voorkeurstaal op basis van hun browserinstellingen of IP-adres en onthoudt de laatst bezochte taal.','Translator Accounts'=>'Vertaleraccounts','Create translator accounts for new users or allow existing users that are not administrators to translate your website.'=>'Maak vertaleraccounts aan voor nieuwe gebruikers of sta bestaande gebruikers die geen beheerder zijn toe om je website te vertalen.','Browse As User Role'=>'Bladeren als gebruikersrol','Navigate your website just like a particular user role would. Really useful for dynamic content or hidden content that appears for particular users.'=>'Navigeer door je website alsof je een bepaalde gebruikersrol hebt. Erg handig voor dynamische content of verborgen content die verschijnt voor specifieke gebruikers.','Navigation Based on Language'=>'Navigatie op basis van taal','Configure different menu items for different languages.'=>'Configureer verschillende menu-items voor verschillende talen.','Different Domain per Language'=>'Ander domein per taal','Connect separate domains or subdomains to each of your translated versions. Strengthen your brand’s local identity and boost SEO performance for every language you support.'=>'Koppel aparte domeinen of subdomeinen aan elk van je vertaalde versies. Versterk de lokale identiteit van je merk en verbeter de SEO-prestaties voor elke taal die je ondersteunt.','Recommended Plugins'=>'Aanbevolen plugins','A short list of plugins you can use to extend your website.'=>'Een korte lijst met plugins die je kunt gebruiken om je website uit te breiden.','Profile Builder'=>'Profile Builder','Capture more user information on the registration form with the help of Profile Builder\'s custom user profile fields and/or add an Email Confirmation process to verify your customers accounts.'=>'Verzamel meer gebruikersinformatie op het registratieformulier met behulp van de aangepaste gebruikersprofielvelden van Profile Builder en/of voeg een e-mailbevestigingsproces toe om de accounts van je klanten te verifiëren.','Paid Member Subscriptions'=>'Paid Member Subscriptions','Accept user payments, create subscription plans and restrict content on your membership site.'=>'Accepteer betalingen van gebruikers, maak abonnementsplannen aan en beperk content op je lidmaatschapssite.','WP Webhooks Automator'=>'WP Webhooks Automator','Create no-code automations and workflows on your WordPress site. Easily connect your plugins, sites and apps together.'=>'Maak no-code automatiseringen en workflows op je WordPress-site. Koppel je plugins, sites en apps eenvoudig aan elkaar.','Save Changes'=>'Wijzigingen opslaan','TranslatePress Errors'=>'TranslatePress-fouten','There are no logged errors.'=>'Er zijn geen gelogde fouten.','Change language'=>'Taal wijzigen','Website language selector'=>'Taalselector voor de website','WordPress Translation Plugin'=>'WordPress-vertaalplugin','Available languages'=>'Beschikbare talen','Language Switcher update notice'=>'Updatemelding taalwisselaar','Legacy language switcher is currently enabled'=>'De verouderde taalwisselaar is momenteel ingeschakeld','We’ve upgraded the switcher for richer customization and a better user experience.<br>In order to use the new configurator, turn off <strong>Load legacy language switcher</strong>.'=>'We hebben de wisselaar geüpgraded voor uitgebreidere aanpassingsmogelijkheden en een betere gebruikerservaring.<br>Schakel <strong>Verouderde taalwisselaar laden</strong> uit om de nieuwe configurator te gebruiken.','Note: You can switch back anytime from <strong>Advanced Settings → <a href="%s">Troubleshooting</a></strong>.'=>'Opmerking: je kunt altijd terugschakelen via <strong>Geavanceerde instellingen → <a href="%s">Probleemoplossing</a></strong>.','Enable the new switcher'=>'De nieuwe schakelaar inschakelen','Your License Key is valid.'=>'Je licentiesleutel is geldig.','Your License Key is invalid.'=>'Je licentiesleutel is ongeldig.','Your License has expired.'=>'Je licentie is verlopen.','Deactivate License'=>'Licentie deactiveren','Add a license key'=>'Licentiesleutel toevoegen','License Key'=>'Licentiesleutel','Manage your license in your %1$s.'=>'Beheer je licentie in je %1$s.','Account Page'=>'accountpagina','Don’t have a TranslatePress AI License Key?'=>'Heb je geen TranslatePress AI-licentiesleutel?','You can get one for %1$sfree%2$s, by creating a free account. It includes:'=>'Je kunt er %1$sgratis%2$s een krijgen door een gratis account aan te maken. Het bevat:','Access to TranslatePress AI for instant automatic translations'=>'Toegang tot TranslatePress AI voor directe automatische vertalingen','2000 AI words to translate automatically'=>'2000 AI-woorden om automatisch te vertalen','Get a free License Today'=>'Vandaag nog een gratis licentie aanvragen','Debug Information'=>'Foutopsporingsinformatie','Debug Data for License Checking'=>'Foutopsporingsgegevens voor licentiecontrole','Debug Data for License Activation'=>'Foutopsporingsgegevens voor licentieactivering','Get more AI words and unlock all features with TranslatePress Pro.'=>'Krijg meer AI-woorden en ontgrendel alle functies met TranslatePress Pro.','Upgrade now ↗'=>'Nu upgraden ↗','Already purchased a Premium version?'=>'Heb je al een Premium-versie aangeschaft?','Go to your %1$s'=>'Ga naar je %1$s','TranslatePress.com Account'=>'TranslatePress.com-account','Download & Install the Pro plugin'=>'Download en installeer de Pro-plug-in','Learn More'=>'Meer informatie','Get a translation volume estimate with a detailed breakdown per page'=>'Ontvang een schatting van het vertaalvolume met een gedetailleerde uitsplitsing per pagina','Find how many translatable words are on your website'=>'Ontdek hoeveel vertaalbare woorden er op je website staan','Enable Automatic Translation'=>'Automatische vertaling inschakelen','To use <strong>DeepL</strong> for automatic translation, activate this Pro add-on from the <a href="%1$s" target="_self" title="%2$s">%2$s</a>.'=>'Om <strong>DeepL</strong> te gebruiken voor automatische vertaling, activeer je deze Pro-add-on vanuit de <a href="%1$s" target="_self" title="%2$s">%2$s</a>.','<strong>DeepL</strong> automatic translation is available as a <a href="%1$s" target="_blank" title="%2$s">%2$s</a>.'=>'Automatische vertaling met <strong>DeepL</strong> is beschikbaar als een <a href="%1$s" target="_blank" title="%2$s">%2$s</a>.','By upgrading you\'ll get access to all paid add-ons, premium support and help fund the future development of TranslatePress.'=>'Door te upgraden krijg je toegang tot alle betaalde add-ons, premium ondersteuning en help je de toekomstige ontwikkeling van TranslatePress te financieren.','Please note that DeepL API usage is paid separately. See <a href="https://www.deepl.com/pro.html#developer">DeepL pricing information</a>.'=>'Let op: het gebruik van de DeepL-API wordt apart betaald. Zie <a href="https://www.deepl.com/pro.html#developer">DeepL-prijsinformatie</a>.','TranslatePress Pro Add-ons'=>'TranslatePress Pro-add-ons','Test API credentials'=>'API-gegevens testen','Check if the selected translation engine is configured correctly.'=>'Controleer of de geselecteerde vertaalengine correct is geconfigureerd.','Alternative Engines'=>'Alternatieve engines','Switch to TranslatePress AI'=>'Overschakelen naar TranslatePress AI','Integrate machine translation directly with your WordPress website.'=>'Machinevertaling rechtstreeks integreren met je WordPress-website.','More info'=>'Meer info','Choose which engine you want to use in order to %1$s automatically translate your website.'=>'Kies welke engine je wilt gebruiken om %1$s je website automatisch te vertalen.','Automatic Translation Settings'=>'Instellingen voor automatische vertaling','AI Words Low Notification'=>'Melding bij laag aantal AI-woorden','Receive an email notification when your TranslatePress AI word count drops below the specified threshold.'=>'Ontvang een e-mailmelding wanneer het aantal woorden voor TranslatePress AI onder de opgegeven drempelwaarde komt.','This feature is only available when using the TranslatePress AI translation engine.'=>'Deze functie is alleen beschikbaar bij gebruik van de vertaalmotor van TranslatePress AI.','Notification Email'=>'Meldingse-mail','The email address where the low AI words notification will be sent.'=>'Het e-mailadres waar de melding over een laag aantal AI-woorden naartoe wordt gestuurd.','Word Threshold'=>'Drempelwaarde','words'=>'woorden','You will be notified when remaining AI words drop below this number.'=>'Je ontvangt een melding wanneer het resterende aantal AI-woorden onder dit getal komt.','Automatically Translate Slugs'=>'Slugs automatisch vertalen','Generate automatic translations of slugs for posts, pages and Custom Post Types.<br/>The slugs will be automatically translated starting with the second refresh of each page.'=>'Genereert automatische vertalingen van slugs voor berichten, pagina\'s en aangepaste berichttypen.<br/>De slugs worden automatisch vertaald vanaf de tweede vernieuwing van elke pagina.','This feature is only available in the paid version. Upgrade TranslatePress and unlock more premium features.'=>'Deze functie is alleen beschikbaar in de betaalde versie. Upgrade TranslatePress en ontgrendel meer premiumfuncties.','Requires <a href="%s" title="TranslatePress Add-on SEO Pack documentation" target="_blank">SEO Pack Add-on</a> to be installed and activated.'=>'Vereist dat de <a href="%s" title="TranslatePress Add-on SEO Pack documentation" target="_blank">SEO Pack-add-on</a> is geïnstalleerd en geactiveerd.','Upgrade now'=>'Nu upgraden','Block Crawlers'=>'Crawlers blokkeren','Block crawlers from triggering automatic translations on your website.<br>This will not prevent crawlers from accessing this site\'s pages.'=>'Blokkeer dat crawlers automatische vertalingen op je website activeren.<br>Dit voorkomt niet dat crawlers de pagina\'s van deze site benaderen.','Limit machine translation / characters per day'=>'Limiet voor automatische vertaling / tekens per dag','Add a limit to the number of automatically translated characters so you can better budget your project.'=>'Stel een limiet in voor het aantal automatisch vertaalde tekens, zodat je je project beter kunt budgetteren.','characters per day'=>'tekens per dag','Today\'s Character Count: '=>'Aantal tekens van vandaag: ','Log machine translation queries.'=>'Machinevertaalqueries loggen.','Only enable for testing purposes. Can impact performance.<br>All records are stored in the wp_trp_machine_translation_log database table. Use a plugin like <a href="https://wordpress.org/plugins/wp-data-access/" target="_blank">WP Data Access</a> to browse the logs or directly from your database manager (PHPMyAdmin, etc.)'=>'Schakel dit alleen in voor testdoeleinden. Kan de prestaties beïnvloeden.<br>Alle records worden opgeslagen in de database-tabel wp_trp_machine_translation_log. Gebruik een plugin zoals <a href="https://wordpress.org/plugins/wp-data-access/" target="_blank">WP Data Access</a> om de logs te bekijken, of rechtstreeks vanuit je databasemanager (PHPMyAdmin, etc.)','Test API Credentials'=>'API-credentials testen','HTTP Referrer: '=>'HTTP Referrer: ','Use this HTTP Referrer if the API lets you restrict key usage from its Dashboard.'=>'Gebruik deze HTTP Referrer als de API je toestaat om sleutelgebruik te beperken vanuit het Dashboard.','Response'=>'Reactie','Response Body'=>'Body van de reactie','Entire Response From wp_remote_get():'=>'Volledige reactie van wp_remote_get():','All Languages'=>'Alle talen','Select the languages you wish to make your website available in.'=>'Selecteer de talen waarin je je website beschikbaar wilt maken.','Formality'=>'Formaliteit','Code'=>'Code','Slug'=>'Slug','Default'=>'Standaard','Formal'=>'Formeel','Informal'=>'Informeel','Language'=>'Taal','This language does not support formality. '=>'Deze taal ondersteunt geen formaliteit. ','Are you sure you want to remove this language?'=>'Weet je zeker dat je deze taal wilt verwijderen?','Custom Languages'=>'Aangepaste talen','To Add more languages activate the Multiple Languages Addon'=>'Om meer talen toe te voegen, activeer je de Multiple Languages-add-on.','You need an active license to add more languages. Verify in your %1$saccount%2$s that your license is valid'=>'Je hebt een actieve licentie nodig om meer talen toe te voegen. Controleer in je %1$saccount%2$s of je licentie geldig is.','Please %1$senter your license%2$s key first to add more languages.'=>'%1$sVoer je licentie%2$s sleutel eerst in om meer talen toe te voegen.','Adding more than two languages is a paid feature. Upgrade TranslatePress and unlock more premium features.'=>'Meer dan twee talen toevoegen is een betaalde functie. Upgrade TranslatePress en ontgrendel meer premiumfuncties.','Website Languages'=>'Websitetalen','Default Language'=>'Standaardtaal','Select the language your content is written in.'=>'Selecteer de taal waarin je inhoud is geschreven.','WARNING. Changing the default language will invalidate existing translations.'=>'WAARSCHUWING. Het wijzigen van de standaardtaal maakt bestaande vertalingen ongeldig.','Even changing from en_US to en_GB, because they are treated as two different languages.'=>'Zelfs bij een wijziging van en_US naar en_GB, omdat deze als twee verschillende talen worden behandeld.','In most cases changing the default flag is all it is needed: '=>'In de meeste gevallen is het wijzigen van de standaardvlag alles wat nodig is: ','replace the default flag'=>'vervang de standaardvlag','Re-run Setup Wizard'=>'Setup-wizard opnieuw uitvoeren','The Setup wizard allows you to quickly setup TranslatePress. You can initiate it at any time.'=>'De setup-wizard stelt je in staat om TranslatePress snel in te stellen. Je kunt deze op elk moment starten.','Language Settings'=>'Taalinstellingen','Use Native language name'=>'Gebruik oorspronkelijke taalnaam','Check if you want to display languages in their native names. Otherwise, languages will be displayed in English.'=>'Vink aan als je talen in hun oorspronkelijke naam wilt weergeven. Anders worden talen in het Engels weergegeven.','Use a subdirectory for the default language'=>'Gebruik een submap voor de standaardtaal','Check if you want to add the subdirectory in the URL for the default language.</br>By checking this option, the default language seen by website visitors will become the first one in the "All Languages" list.'=>'Vink aan als je een submap voor de standaardtaal aan de URL wilt toevoegen.</br>Door deze optie aan te vinken wordt de standaardtaal die websitebezoekers zien de eerste in de lijst \'Alle talen\'.','Force language in custom links'=>'Taal afdwingen in aangepaste links','Select Yes if you want to force custom links without language encoding to keep the currently selected language.'=>'Selecteer Ja als je aangepaste links zonder taalcodering wilt forceren om de momenteel geselecteerde taal te behouden.','Shortcode '=>'Shortcode ','Use shortcode on any page or widget.'=>'Gebruik shortcode op elke pagina of widget.','You can also add the <a href="%s" title="Language Switcher Block Documentation">Language Switcher Block</a> in the WP Gutenberg Editor.'=>'Je kunt ook het <a href="%s" title="Language Switcher Block Documentation">Taalwisselblok</a> toevoegen in de WP Gutenberg-editor.','Menu item'=>'Menu-item','Go to  %1$s Appearance -> Menus%2$s to add languages to the Language Switcher in any menu.'=>'Ga naar  %1$s Weergave -> Menu\'s%2$s om talen toe te voegen aan de taalwisselaar in elk menu.','Learn more in our documentation.'=>'Lees meer in onze documentatie.','Floating language selection'=>'Zwevende taalselectie','Add a floating dropdown that follows the user on every page.'=>'Voeg een zwevende dropdown toe die de gebruiker op elke pagina volgt.','Show "Powered by TranslatePress"'=>'"Powered by TranslatePress" weergeven','Show the small "Powered by TranslatePress" label in the floater language switcher.'=>'Toon het kleine "Powered by TranslatePress"-label in de zwevende taalwisselaar.','5 Days to Better Multilingual Websites'=>'5 dagen naar betere meertalige websites','%sJoin our FREE & EXCLUSIVE onboarding course%s and learn how to grow your multilingual traffic, reach international markets, and save time & money while getting the most out of TranslatePress!'=>'%sDoe mee met onze GRATIS & EXCLUSIEVE onboardingcursus%s en leer hoe je je meertalige verkeer laat groeien, internationale markten bereikt en tijd & geld bespaart terwijl je het meeste uit TranslatePress haalt!','Invalid email address'=>'Ongeldig e-mailadres','Your email'=>'Je e-mailadres','Sign me up!'=>'Meld me aan!','Sign up with your email address and receive a 5-part email guide to help you maximize the power of TranslatePress.'=>'Meld je aan met je e-mailadres en ontvang een e-mailgids in 5 delen om het meeste uit TranslatePress te halen.','Dismiss email course notification'=>'E-mailcursusmelding sluiten','Hey %s,<br>Never miss an important update - opt in to our security and feature updates notifications, and non-sensitive diagnostic tracking.'=>'Hey %s,<br>Mis nooit een belangrijke update - meld je aan voor onze meldingen over beveiligings- en functie-updates, en niet-gevoelige diagnostische tracking.','Allow & Continue'=>'Toestaan & doorgaan','Skip'=>'Overslaan','This will allow TranslatePress to:'=>'Dit stelt TranslatePress in staat om:','Your profile overview'=>'Je profieloverzicht','Name and email address'=>'Naam en e-mailadres','Admin Notices'=>'Beheerdersmeldingen','Updates, announcements, marketing, no spam'=>'Updates, aankondigingen, marketing, geen spam','Plugin status & settings'=>'Pluginstatus en instellingen','Active, Deactivated, installed version and settings'=>'Actief, gedeactiveerd, geïnstalleerde versie en instellingen','Privacy Policy'=>'Privacybeleid','Terms of Service'=>'Servicevoorwaarden','Support'=>'Ondersteuning','Documentation'=>'Documentatie','Add Extra AI Words'=>'Extra AI-woorden toevoegen','Optimize TranslatePress database tables'=>'TranslatePress-databasetabellen optimaliseren','<strong>IMPORTANT NOTE:</strong> Before performing this action it is strongly recommended to first backup the database.'=>'<strong>BELANGRIJKE OPMERKING:</strong> Het wordt sterk aanbevolen om eerst een back-up van de database te maken voordat je deze actie uitvoert.','IMPORTANT: It is strongly recommended to first backup the database!! Are you sure you want to continue?'=>'BELANGRIJK: Het wordt sterk aanbevolen om eerst een back-up van de database te maken!! Weet je zeker dat je wilt doorgaan?','Operations to perform'=>'Uit te voeren bewerkingen','Remove CDATA for original and dictionary strings'=>'CDATA verwijderen voor originele en woordenboektekenreeksen','Removes CDATA from trp_original_strings and trp_dictionary_* tables.<br>This type of content should not be detected by TranslatePress. It might have been introduced in the database in older versions of the plugin.'=>'Verwijdert CDATA uit de tabellen trp_original_strings en trp_dictionary_*.<br>Dit type inhoud zou niet door TranslatePress gedetecteerd moeten worden. Het kan in de database zijn geïntroduceerd door oudere versies van de plugin.','Remove untranslated links from dictionary tables'=>'Onvertaalde links uit woordenboektabellen verwijderen','Removes untranslated links and images from all trp_dictionary_* tables. These tables contain translations for user-inputted strings such as post content, post title, menus etc.'=>'Verwijdert onvertaalde links en afbeeldingen uit alle trp_dictionary_*-tabellen. Deze tabellen bevatten vertalingen voor door de gebruiker ingevoerde tekenreeksen, zoals berichtinhoud, berichttitel, menu\'s, etc.','Remove duplicate rows for gettext strings'=>'Dubbele rijen voor Gettext-tekenreeksen verwijderen','Cleans up all trp_gettext_* tables of duplicate rows. These tables contain translations for themes and plugin strings.'=>'Ruimt dubbele rijen op in alle trp_gettext_*-tabellen. Deze tabellen bevatten vertalingen voor thema- en plugintekenreeksen.','Remove duplicate rows for dictionary strings'=>'Dubbele rijen voor woordenboektekenreeksen verwijderen','Cleans up all trp_dictionary_* tables of duplicate rows. These tables contain translations for user-inputted strings such as post content, post title, menus etc.'=>'Ruimt dubbele rijen op in alle trp_dictionary_*-tabellen. Deze tabellen bevatten vertalingen voor door de gebruiker ingevoerde tekenreeksen, zoals berichtinhoud, berichttitel, menu\'s, etc.','Remove duplicate rows for original dictionary strings'=>'Dubbele rijen voor originele woordenboektekenreeksen verwijderen','Cleans up all trp_original_strings table of duplicate rows. This table contains strings in the default language, without any translation.<br>The trp_original_meta table, which contains meta information that refers to the post parent’s ID, is also regenerated.<br>Such duplicates can appear in exceptional situations of unexpected behavior.'=>'Ruimt dubbele rijen op in de tabel trp_original_strings. Deze tabel bevat tekenreeksen in de standaardtaal, zonder enige vertaling.<br>De tabel trp_original_meta, die meta-informatie bevat die verwijst naar de ID van het bovenliggende bericht, wordt ook opnieuw gegenereerd.<br>Dergelijke duplicaten kunnen voorkomen in uitzonderlijke situaties van onverwacht gedrag.','Replace gettext strings that have original ID NULL with the correct original IDs'=>'Gettext-tekenreeksen met originele ID NULL vervangen door de juiste originele ID\'s','Fixes an edge case issue where some gettext strings have the original ID incorrectly set to NULL, causing problems in the Translation Editor.<br>This operation corrects the original IDs in the trp_gettext_* tables.<br>Only check this option if you encountered an issue in the Translation Editor where clicking the green pencil did not bring up the gettext string for translation in the left sidebar.<br>Otherwise, please leave this option unchecked because it\'s an intensive operation.'=>'Verhelpt een probleem bij een randgeval waarbij sommige Gettext-tekenreeksen de originele ID incorrect op NULL hebben staan, wat problemen veroorzaakt in de vertaaleditor.<br>Deze bewerking corrigeert de originele ID\'s in de trp_gettext_*-tabellen.<br>Schakel deze optie alleen in als je een probleem bent tegengekomen in de vertaaleditor waarbij de Gettext-tekenreeks niet verscheen voor vertaling in de linkerzijbalk na het klikken op het groene potlood.<br>Laat deze optie anders uitgeschakeld staan, omdat het een intensieve bewerking is.','Optimize Database'=>'Database optimaliseren','TranslatePress Database Updater'=>'TranslatePress Database Updater','Updating TranslatePress tables. Please leave this window open.'=>'Bezig met het bijwerken van de TranslatePress-tabellen. Laat dit venster open.','The inactive languages will still be visible and active for the admin. For other users they won\'t be visible in the language switchers and won\'t be accessible either.'=>'De inactieve talen zijn nog steeds zichtbaar en actief voor de beheerder. Voor andere gebruikers zijn ze niet zichtbaar in de taalschakelaars en ook niet toegankelijk.','unknown'=>'onbekend','<strong>Extra Languages add-on</strong> requires TranslatePress version %1$s or higher. You are currently using version %2$s. Please update TranslatePress to enable this feature.'=>'<strong>Extra Languages add-on</strong> vereist TranslatePress versie %1$s of hoger. Je gebruikt momenteel versie %2$s. Werk TranslatePress bij om deze functie in te schakelen.','Automatic and manual slug translation changes performed when <strong>TranslatePress - Multilingual</strong> 2.8.4 was active had to be removed because of some issues with that version. All slug translations from before that version are now in use. Thank you for understanding!'=>'Automatische en handmatige wijzigingen aan slug-vertalingen die zijn uitgevoerd toen <strong>TranslatePress - Multilingual</strong> 2.8.4 actief was, moesten worden verwijderd vanwege enkele problemen met die versie. Alle slug-vertalingen van vóór die versie zijn nu in gebruik. Bedankt voor je begrip!','If you absolutely need them, the removed translations can be found in tables trp_slug_original_obsolete and trp_slug_translation_obsolete.'=>'Als je ze absoluut nodig hebt, zijn de verwijderde vertalingen te vinden in de tabellen trp_slug_original_obsolete en trp_slug_translation_obsolete.','View Docs'=>'Documentatie bekijken','Assign different domains or subdomains to each language. When visitors access these domains, TranslatePress loads the appropriate language translation directly without redirecting.'=>'Wijs aan elke taal verschillende domeinen of subdomeinen toe. Wanneer bezoekers deze domeinen bezoeken, laadt TranslatePress direct de juiste taalvertaling zonder door te sturen.','Example: %1$s for English, %2$s for Spanish, %3$s for French.'=>'Voorbeeld: %1$s voor Engels, %2$s voor Spaans, %3$s voor Frans.','Before enabling:'=>'Voor het inschakelen:','Ensure your domains are registered, pointed to your server, and have SSL certificates configured.'=>'Zorg ervoor dat je domeinen geregistreerd zijn, naar je server wijzen en voorzien zijn van geconfigureerde SSL-certificaten.','Domain'=>'Domein','Map this language to a different domain or sub-domain.'=>'Koppel deze taal aan een ander domein of subdomein.','https://example.com'=>'https://example.com','Prefill with current domain'=>'Huidig domein voorinvullen','Check DNS'=>'DNS controleren','Checking DNS...'=>'DNS wordt gecontroleerd...','DNS is correctly configured!'=>'DNS is correct geconfigureerd!','DNS check failed. Please verify your domain configuration.'=>'DNS-controle mislukt. Controleer je domeinconfiguratie.','This domain is already assigned to another language.'=>'Dit domein is al toegewezen aan een andere taal.','<strong>Different Domain per Language add-on</strong> requires TranslatePress version %1$s or higher. You are currently using version %2$s. Please update TranslatePress to enable this feature.'=>'<strong>Different Domain per Language add-on</strong> vereist TranslatePress versie %1$s of hoger. Je gebruikt momenteel versie %2$s. Update TranslatePress om deze functie te activeren.','Note: This option is disabled when Different Domain for Language addon is active.'=>'Opmerking: deze optie is uitgeschakeld wanneer de Different Domain for Language add-on actief is.','Different Domain per Language: Domain is required when domain mapping is enabled. The toggle has been disabled for languages with empty domains.'=>'Different Domain per Language: een domein is vereist wanneer domeinmapping is ingeschakeld. De schakelaar is uitgeschakeld voor talen met lege domeinen.','Different Domain per Language: The same domain cannot be assigned to multiple languages. The toggle has been disabled for duplicate domains.'=>'Different Domain per Language: hetzelfde domein kan niet aan meerdere talen worden toegewezen. De schakelaar is uitgeschakeld voor dubbele domeinen.','Different Domain per Language: A language domain cannot be the same as the main site URL. The toggle has been disabled for the matching domain.'=>'Different Domain per Language: een taaldomein kan niet hetzelfde zijn als de URL van de hoofdsite. De schakelaar is uitgeschakeld voor het overeenkomstige domein.','Please enter a domain.'=>'Voer een domein in.','Invalid domain format.'=>'Ongeldig domeinformaat.','Could not reach domain: %s'=>'Kan domein niet bereiken: %s','Domain returned HTTP status %d.'=>'Domein gaf HTTP-status %d terug.','Domain is reachable!'=>'Domein is bereikbaar!','Limit this menu item to the following languages'=>'Beperk dit menu-item tot de volgende talen','Date format'=>'Datumopmaak','Customize the date formatting per each translated language.<br/>Leave empty for default WP setting or see more information <a href="https://wordpress.org/support/article/formatting-date-and-time/" title="Formatting Date and Time" target="_blank">here</a>'=>'Pas de datumopmaak aan voor elke vertaalde taal.<br/>Laat leeg voor de standaard WP-instelling of zie <a href="https://wordpress.org/support/article/formatting-date-and-time/" title="Formatting Date and Time" target="_blank">hier</a> meer informatie.','To edit an existing TranslatePress language, input the language code and fill in only the columns you want to overwrite (e.g. Language name, Flag).<br>You can also add new custom languages. They will be available under General settings, All Languages list, where the URL slug can be edited.'=>'Om een bestaande TranslatePress-taal te bewerken, voer je de taalcode in en vul je alleen de kolommen in die je wilt overschrijven (bijv. Taalnaam, Vlag).<br>Je kunt ook nieuwe aangepaste talen toevoegen. Deze zijn beschikbaar onder Algemene instellingen, in de lijst Alle talen, waar de URL-slug kan worden bewerkt.','For custom flag, first upload the image in media library then paste the URL.<br>Changing or deleting a custom language will impact translations and site URL\'s.<br>The Language code and the ISO Code should contain only alphabetical values, numerical values, "-" and "_".<br>The ISO Codes can be found on <a href = "https://cloud.google.com/translate/docs/languages" target = "_blank">Google ISO Codes</a> and <a href = "https://www.deepl.com/docs-api/translating-text/" target = "_blank">DeepL Target Codes</a>.'=>'Voor een aangepaste vlag upload je eerst de afbeelding in de mediabibliotheek en plak je vervolgens de URL.<br>Het wijzigen of verwijderen van een aangepaste taal heeft gevolgen voor vertalingen en site-URL\'s.<br>De taalcode en de ISO-code mogen alleen alfabetische waarden, numerieke waarden, "-" en "_" bevatten.<br>De ISO-codes zijn te vinden op <a href = "https://cloud.google.com/translate/docs/languages" target = "_blank">Google ISO-codes</a> en <a href = "https://www.deepl.com/docs-api/translating-text/" target = "_blank">DeepL-doelcodes</a>.','Language code'=>'Taalcode','Language name'=>'Taalnaam','Native name'=>'Naam in eigen taal','ISO Code'=>'ISO-code','Flag URL'=>'Vlag-URL','Text RTL'=>'RTL-tekst','Custom language'=>'Aangepaste taal','Disable dynamic translation'=>'Dynamische vertaling uitschakelen','It disables detection of strings displayed dynamically using JavaScript. <br/>Strings loaded via a server side AJAX call will still be translated.'=>'Dit schakelt de detectie uit van tekenreeksen die dynamisch via JavaScript worden weergegeven.<br/>Tekenreeksen die via een server-side AJAX-aanroep worden geladen, worden nog steeds vertaald.','Disable translation for gettext strings'=>'Vertaling van Gettext-tekenreeksen uitschakelen','Gettext Strings are strings outputted by themes and plugins. <br> Translating these types of strings through TranslatePress can be unnecessary if they are already translated using the .po/.mo translation file system.<br>Enabling this option can improve the page load performance of your site in certain cases. The disadvantage is that you can no longer edit gettext translations using TranslatePress, nor benefit from automatic translation on these strings.'=>'Gettext-tekenreeksen zijn tekenreeksen die door thema\'s en plugins worden gegenereerd. <br> Het vertalen van dit soort tekenreeksen via TranslatePress kan onnodig zijn als ze al zijn vertaald met het .po/.mo-vertaalbestandssysteem.<br>Door deze optie in te schakelen kan in bepaalde gevallen de paginalaadtijd van je site verbeteren. Het nadeel is dat je gettext-vertalingen niet langer kunt bewerken met TranslatePress, en ook geen gebruik kunt maken van automatische vertaling voor deze tekenreeksen.','Gettext Strings translation is disabled'=>'Vertaling van Gettext-tekenreeksen is uitgeschakeld','To enable it go to '=>'Om dit in te schakelen ga naar ','TranslatePress->Advanced Settings->Debug->Disable translation for gettext strings'=>'TranslatePress->Geavanceerde instellingen->Debug->Vertaling uitschakelen voor gettext-strings',' and uncheck the Checkbox.'=>' en schakel het selectievakje uit.','Dismiss'=>'Negeren','Exclude translated links from sitemap'=>'Vertaalde links uitsluiten van sitemap','Do not include translated links in sitemaps generated by SEO plugins.<br/>Requires <a href="https://translatepress.com/docs/addons/seo-pack/?utm_source=tp-advanced&utm_medium=client-site&utm_campaign=miscellaneous" title="TranslatePress Add-on SEO Pack documentation" target="_blank"> SEO Pack Add-on</a> to be installed and activated.'=>'Vertaalde links niet opnemen in sitemaps die door SEO-plugins worden gegenereerd.<br/>Vereist dat de <a href="https://translatepress.com/docs/addons/seo-pack/?utm_source=tp-advanced&utm_medium=client-site&utm_campaign=miscellaneous" title="TranslatePress Add-on SEO Pack documentation" target="_blank"> SEO Pack Add-on</a> is geïnstalleerd en geactiveerd.','Disable post container tags for post title'=>'Container-tags voor berichttitel uitschakelen','It disables search indexing the post title in translated languages.<br/>Useful when the title of the post doesn\'t allow HTML thus breaking the page.'=>'Dit schakelt het zoekindexeren van de berichttitel in vertaalde talen uit.<br/>Nuttig wanneer de titel van het bericht geen HTML toestaat, waardoor de pagina wordt verbroken.','Disable post container tags for post content'=>'Container-tags voor berichtinhoud uitschakelen','It disables search indexing the post content in translated languages.<br/>Useful when the content of the post doesn\'t allow HTML thus breaking the page.'=>'Dit schakelt het zoekindexeren van de berichtinhoud in vertaalde talen uit.<br/>Nuttig wanneer de inhoud van het bericht geen HTML toestaat, waardoor de pagina wordt verbroken.','Do not translate certain paths'=>'Bepaalde paden niet vertalen','Choose what paths can be translated. Supports wildcard at the end of the path.<br>For example, to exclude https://example.com/some/path you can either use the rule /some/path/ or /some/*.<br>Enter each rule on it\'s own line. To exclude the home page use {{home}}.'=>'Kies welke paden vertaald kunnen worden. Ondersteunt een wildcard aan het einde van het pad.<br>Bijvoorbeeld, om https://example.com/some/path uit te sluiten, kun je de regel /some/path/ of /some/* gebruiken.<br>Voer elke regel op een eigen regel in. Om de startpagina uit te sluiten, gebruik je {home}.','Exclude Paths From Translation'=>'Paden uitsluiten van vertaling','Translate Only Certain Paths'=>'Alleen bepaalde paden vertalen','Enable the hreflang x-default tag for language:'=>'De hreflang x-default-tag inschakelen voor taal:','Enables the hreflang="x-default" for an entire language. See documentation for more details.'=>'Schakelt de hreflang="x-default" in voor een hele taal. Zie de documentatie voor meer details.','Translate numbers and numerals'=>'Getallen en cijfers vertalen','Enable translation of numbers ( e.g. phone numbers)'=>'Vertaling van nummers inschakelen ( bijv. telefoonnummers)','Selector'=>'Selector','Exclude from dynamic translation'=>'Uitsluiten van dynamische vertaling','Do not dynamically translate strings that are found in html nodes matching these selectors.<br>Excludes all the children of HTML nodes matching these selectors from being translated using JavaScript.<br/>These strings will still be translated on the server side if possible.'=>'Vertaal geen tekenreeksen dynamisch die worden gevonden in HTML-nodes die overeenkomen met deze selectors.<br>Sluit alle onderliggende elementen van HTML-nodes die overeenkomen met deze selectors uit van vertaling via JavaScript.<br/>Deze tekenreeksen worden indien mogelijk nog steeds aan de serverzijde vertaald.','Gettext String'=>'Gettext-tekenreeks','Exclude Gettext Strings'=>'Gettext-tekenreeksen uitsluiten','Exclude these strings from being translated as Gettext strings by TranslatePress. Leave the domain empty to take into account any Gettext string.<br/>Can still be translated through po/mo files.'=>'Sluit deze tekenreeksen uit van vertaling als Gettext-tekenreeksen door TranslatePress. Laat het domein leeg om op elke Gettext-tekenreeks van toepassing te zijn.<br/>Ze kunnen nog steeds via po/mo-bestanden worden vertaald.','Exclude selectors only from automatic translation'=>'Selectors alleen uitsluiten van automatische vertaling','Do not automatically translate strings that are found in html nodes matching these selectors.<br>Excludes all the children of HTML nodes matching these selectors from being automatically translated.<br>Manual translation of these strings is still possible.'=>'Vertaal geen tekenreeksen automatisch die worden gevonden in HTML-nodes die overeenkomen met deze selectors.<br>Sluit alle onderliggende elementen van HTML-nodes die overeenkomen met deze selectors uit van automatische vertaling.<br>Handmatige vertaling van deze tekenreeksen is nog steeds mogelijk.','Exclude selectors from translation'=>'Selectors uitsluiten van vertaling','Do not translate strings that are found in html nodes matching these selectors.<br>Excludes all the children of HTML nodes matching these selectors from being translated.<br>These strings cannot be translated manually nor automatically.'=>'Vertaal geen tekenreeksen die worden gevonden in HTML-nodes die overeenkomen met deze selectors.<br>Sluit alle onderliggende elementen van HTML-nodes die overeenkomen met deze selectors uit van vertaling.<br>Deze tekenreeksen kunnen noch handmatig noch automatisch worden vertaald.','String'=>'Tekenreeks','Exclude strings from automatic translation'=>'Tekenreeksen uitsluiten van automatische vertaling','Do not automatically translate these strings (ex. names, technical words...)<br>Paragraphs containing these strings will still be translated except for the specified part.'=>'Vertaal deze tekenreeksen niet automatisch (bijv. namen, technische termen...)<br>Alinea\'s die deze tekenreeksen bevatten, worden nog steeds vertaald, behalve het opgegeven deel.','Fix broken HTML'=>'Gebroken HTML repareren','General attempt to fix broken or missing HTML on translated pages.<br/>'=>'Algemene poging om gebroken of ontbrekende HTML op vertaalde pagina\'s te repareren.<br/>','Force slash at end of home url:'=>'Forceer slash aan einde van home-URL:','Ads a slash at the end of the home_url() function'=>'Voegt een slash toe aan het einde van de home_url()-functie','Show Both (recommended)'=>'Beide tonen (aanbevolen)','Remove Country Locale'=>'Land-locale verwijderen','Remove Region Independent Locale'=>'Regio-onafhankelijke locale verwijderen','Remove duplicate hreflang'=>'Dubbele hreflang verwijderen','Choose which hreflang tags will appear on your website.<br/>We recommend showing both types of hreflang tags as indicated by <a href="https://developers.google.com/search/docs/advanced/crawling/localized-versions" title="Google Crawling" target="_blank">Google documentation</a>.<br/>Removing Country Locale when having multiple Country Locales of the same language (ex. English UK and English US) will result in showing one hreflang tag with link to just one of the region locales for that language.'=>'Kies welke hreflang-tags op je website worden weergegeven.<br/>We raden aan om beide soorten hreflang-tags weer te geven, zoals aangegeven in de <a href="https://developers.google.com/search/docs/advanced/crawling/localized-versions" title="Google Crawling" target="_blank">Google-documentatie</a>.<br/>Het verwijderen van Country Locale wanneer je meerdere Country Locales van dezelfde taal hebt (bijv. English UK en English US) resulteert in het tonen van één hreflang-tag met een link naar slechts één van de regionale locales voor die taal.','Default (example: en-US, fr-CA, etc.)'=>'Standaard (voorbeeld: en-US, fr-CA, etc.)','Regional (example: en, fr, es, etc.)'=>'Regionaal (voorbeeld: en, fr, es, etc.)','HTML Lang Attribute Format'=>'HTML-lang-attribuutformaat','Change lang attribute of the html tag to a format that includes country regional or not. <br>In HTML, the lang attribute (<html lang="en-US">)  should be used to  specify the language of text content so that the  browser can correctly display or process  your content (eg. for  hyphenation, styling, spell checking, etc).'=>'Wijzig het lang-attribuut van de html-tag naar een formaat dat een landregio bevat of niet. <br>In HTML moet het lang-attribuut (<html lang="en-US">) worden gebruikt om de taal van tekstinhoud op te geven, zodat de browser je inhoud correct kan weergeven of verwerken (bijv. voor woordafbreking, opmaak, spellingscontrole, etc).','Load legacy Language Switcher'=>'Oude taalschakelaar laden','Applies to all types of language switchers (floating, shortcode, and menu). When enabled, the site will revert to using the original Language Switcher configured in the General Settings tab, replacing the new customizable version. Your existing switcher settings will remain saved, but they will be ignored while this option is active.'=>'Is van toepassing op alle soorten taalschakelaars (zwevend, shortcode en menu). Wanneer ingeschakeld, zal de site terugvallen op het gebruik van de originele taalschakelaar die is geconfigureerd op het tabblad Algemene instellingen, waarbij de nieuwe aanpasbare versie wordt vervangen. Je bestaande instellingen voor de taalschakelaar blijven bewaard, maar worden genegeerd zolang deze optie actief is.','Load legacy SEO Pack Add-On'=>'Oude SEO Pack-add-on laden','In case the recent migration to the new slug rewrite is causing trouble, set this to Yes to use the old method <br> Please <a href="https://translatepress.com/support/open-ticket/?utm_source=tp-advanced&utm_medium=client-site&utm_campaign=troubleshooting" target="_blank">open a support ticket</a> letting us know of the issues you are having.'=>'Als de recente migratie naar de nieuwe slug-rewrite problemen veroorzaakt, stel dit dan in op Ja om de oude methode te gebruiken <br> <a href="https://translatepress.com/support/open-ticket/?utm_source=tp-advanced&utm_medium=client-site&utm_campaign=troubleshooting" target="_blank">Open een supportticket</a> en laat ons weten welke problemen je ondervindt.','Manual Translation Only'=>'Alleen handmatige vertaling','TranslatePress pro-actively scans and saves strings in the database when users access translated pages. <br>This setting disables this functionality and only allows translation and string saving when inside the Translation Editor. <br>Also disables machine translation outside the Translation Editor, giving you better control over character spending, by translating only the pages you visit in the Translation Editor.'=>'TranslatePress scant proactief tekenreeksen op in de database wanneer gebruikers vertaalde pagina\'s bezoeken. <br>Deze instelling schakelt deze functionaliteit uit en staat alleen vertaling en opslaan van tekenreeksen toe wanneer je in de Translation Editor bent. <br>Schakelt ook automatische vertaling uit buiten de Translation Editor, waardoor je betere controle krijgt over je tekensverbruik, door alleen de pagina\'s te vertalen die je in de Translation Editor bezoekt.','Open language switcher only on click'=>'Taalschakelaar alleen openen bij klik','Open the language switcher shortcode by clicking on it instead of hovering.<br> Close it by clicking on it, anywhere else on the screen or by pressing the escape key. This will affect only the shortcode language switcher.'=>'Open de taalschakelaar-shortcode door erop te klikken in plaats van eroverheen te hoveren.<br>Sluit deze door erop te klikken, ergens anders op het scherm of door op de Escape-toets te drukken. Dit heeft alleen effect op de shortcode-taalschakelaar.','Show opposite language in the language switcher'=>'Tegenovergestelde taal tonen in de taalschakelaar','Transforms the language switcher into a button showing the other available language, not the current one.<br> Only works when there are exactly two languages, the default one and a translation one.<br>This will affect the shortcode language switcher and floating language switcher as well.<br> To achieve this in menu language switcher go to Appearance->Menus->Language Switcher and select Opposite Language.'=>'Transformeert de taalschakelaar in een knop die de andere beschikbare taal toont, niet de huidige.<br> Werkt alleen wanneer er precies twee talen zijn: de standaardtaal en een vertaaltaal.<br>Dit heeft ook effect op de shortcode-taalschakelaar en de zwevende taalschakelaar.<br> Om dit te bereiken in de menu-taalschakelaar ga je naar Weergave->Menu\'s->Taalschakelaar en selecteer je Tegenovergestelde taal.','<a href="%s">Click here</a> to access the database optimization tool.'=>'<a href="%s">Klik hier</a> om de database-optimalisatietool te openen.','It helps remove possible duplicate translations, clear unnecessary data and repair possible metadata issues.'=>'Het helpt mogelijke dubbele vertalingen te verwijderen, onnodige gegevens op te schonen en mogelijke metadata-problemen te repareren.','<a href="%s" target="_blank">Here</a> you can observe the last 5 SQL errors relevant to TranslatePress if they exist.'=>'<a href="%s" target="_blank">Hier</a> kun je de laatste 5 SQL-fouten bekijken die relevant zijn voor TranslatePress, als deze bestaan.','Troubleshooting'=>'Probleemoplossing','Exclude Gettext strings'=>'Gettext-tekenreeksen uitsluiten','Debug'=>'Foutopsporing','Custom languages'=>'Aangepaste talen','Miscellaneous options'=>'Diverse opties','Exclude strings & pages'=>'Tekenreeksen en pagina\'s uitsluiten','Automatic Translation Memory'=>'Automatisch vertaalgeheugen','Serve same translation for similar text. The strings need to have a percentage of 95% similarity.<br>Helps prevent losing existing translation when correcting typos or making minor adjustments to the original text. <br>If a translation already exists for a very similar original string, it will automatically be used for the current original string.<br>Does not work when making changes to a text that is part of a translation block unless the new text is manually merged again in a translation block.<br>Each string needs to have a minimum of 50 characters.'=>'Gebruik dezelfde vertaling voor vergelijkbare tekst. De tekenreeksen moeten een overeenkomst van 95% hebben.<br>Helpt bij het voorkomen van het verlies van bestaande vertalingen bij het corrigeren van typefouten of het aanbrengen van kleine wijzigingen in de originele tekst. <br>Als er al een vertaling bestaat voor een zeer vergelijkbare originele tekenreeks, wordt deze automatisch gebruikt voor de huidige originele tekenreeks.<br>Werkt niet wanneer u wijzigingen aanbrengt in een tekst die deel uitmaakt van een vertaalblok, tenzij de nieuwe tekst handmatig opnieuw wordt samengevoegd in een vertaalblok.<br>Elke tekenreeks moet minimaal 50 tekens bevatten.','WARNING: This feature can negatively impact page loading times in secondary languages, particularly with large databases (for example websites with a lot of pages or products). If you experience slow loading times, disable this and try again.'=>'WAARSCHUWING: Deze functie kan de paginalaadtijden negatief beïnvloeden in secundaire talen, met name bij grote databases (bijvoorbeeld websites met veel pagina\'s of producten). Als je trage laadtijden ervaart, schakel dit dan uit en probeer het opnieuw.','Fix missing dynamic content'=>'Ontbrekende dynamische inhoud herstellen','May help fix missing content inserted using JavaScript. <br> It shows dynamically inserted content in original language for a moment before the translation request is finished.'=>'Kan helpen om ontbrekende inhoud die via JavaScript is ingevoegd te herstellen. <br> Het toont dynamisch ingevoegde inhoud kort in de originele taal voordat het vertaalverzoek is voltooid.','Filter Gettext wrapping from post content and title'=>'Filter Gettext-wrapping uit berichtinhoud en -titel','Filters gettext wrapping such as #!trpst#trp-gettext from all updated post content and post title. Does not affect previous post content. <br/><strong>Database backup is recommended before switching on.</strong>'=>'Filtert Gettext-wrapping zoals #!trpst#trp-gettext uit alle bijgewerkte berichtinhoud en berichttitels. Heeft geen invloed op eerdere berichtinhoud. <br/><strong>Een database-back-up wordt aanbevolen voordat u dit inschakelt.</strong>','Filter Gettext wrapping from post meta'=>'Filter Gettext-wrapping uit berichtmeta','Filters gettext wrapping such as #!trpst#trp-gettext from all updated post meta. Does not affect previous post meta. <br/><strong>Database backup is recommended before switching on.</strong>'=>'Filtert Gettext-wrapping zoals #!trpst#trp-gettext uit alle bijgewerkte berichtmeta. Heeft geen invloed op eerdere berichtmeta. <br/><strong>Een database-back-up wordt aanbevolen voordat u dit inschakelt.</strong>','Google Translate v2'=>'Google Translate v2','Google Translate API Key'=>'Google Translate API-sleutel','Add your API Key here...'=>'Voeg hier je API-sleutel toe...','Visit <a href="https://cloud.google.com/docs/authentication/api-keys" target="_blank">this link</a> to see how you can set up an API key, <strong>control API costs</strong> and set HTTP referrer restrictions.'=>'Bezoek <a href="https://cloud.google.com/docs/authentication/api-keys" target="_blank">deze link</a> om te zien hoe je een API-sleutel instelt, <strong>API-kosten beheert</strong> en HTTP-referrerbeperkingen instelt.','Your HTTP referrer is: %s'=>'Je HTTP-referrer is: %s','There was an error on the server processing your Google Translate key.'=>'Er is een fout opgetreden op de server bij het verwerken van je Google Translate-sleutel.','There was an error with your Google Translate key.'=>'Er is een fout opgetreden met je Google Translate-sleutel.','Please check your TranslatePress license key.'=>'Controleer je TranslatePress-licentiesleutel.','TranslatePress AI'=>'TranslatePress AI','No Active License Detected for this website.'=>'Geen actieve licentie gedetecteerd voor deze website.','In order to enable Automatic Translation using TranslatePress AI, you need a license key by creating a free account.'=>'Om automatische vertaling met TranslatePress AI in te schakelen, moet je een gratis account aanmaken om een licentiesleutel te verkrijgen.','Create your Free Account'=>'Maak je gratis account aan',' or '=>' of ','Enter your license key'=>'Voer je licentiesleutel in',' 